#!/usr/bin/env node
/**
 * generate-capsule-client — emit a typed frontend client that matches CAPSULE'S
 * conventions (manifest/capsule-conventions.json): domain read paths, real read
 * envelopes ({ <entityCamelPlural> }), canonical dispatcher writes ({ success,result,events }),
 * apiFetch, and the generated entity types. Replaces stock client paths that 404.
 *
 * Run: pnpm manifest:client   (or: node manifest/scripts/generate-capsule-client.mjs)
 * Outputs (DO NOT EDIT): apps/app/app/lib/manifest-types.generated.ts + manifest-client.generated.ts
 */
import { readFileSync, writeFileSync, mkdtempSync, readdirSync, statSync } from "node:fs";
import { execSync } from "node:child_process";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { ENTITY_DOMAIN_MAP } from "./entity-domain-map.mjs";

const conv = JSON.parse(readFileSync("manifest/capsule-conventions.json", "utf8"));
const ir = JSON.parse(readFileSync("manifest/ir/kitchen.ir.json", "utf8"));
const camel = (s) => s.charAt(0).toLowerCase() + s.slice(1);
const cap = (s) => s.charAt(0).toUpperCase() + s.slice(1);
const plural = (s) => /(s|x|z|ch|sh)$/.test(s) ? s + "es" : /y$/.test(s) ? s.slice(0, -1) + "ies" : s + "s";

// 1) TYPES: generate via the official projection, copy into the app lib.
const tdir = mkdtempSync(join(tmpdir(), "mf-types-"));
execSync(`pnpm exec manifest generate manifest/ir/kitchen.ir.json --surface types --output "${tdir}"`, { stdio: "pipe" });
function find(dir, name) {
  for (const e of readdirSync(dir)) {
    const p = join(dir, e);
    if (statSync(p).isDirectory()) { const r = find(p, name); if (r) return r; }
    else if (e === name) return p;
  }
  return null;
}
const typesFile = find(tdir, "manifest-generated.ts");
const typesContent = readFileSync(typesFile, "utf8");
// The stock `types` surface emits raw Manifest scalar names (int/decimal/money/array/Date)
// as TS types, which don't compile. Map them to TS per Capsule's wire conventions
// (dates are ISO strings on the wire — manifest/capsule-conventions.json dateSerialization).
function toTsTypes(src) {
  return src
    .replace(/:\s*(int|bigint|float|decimal|money|number)\b/g, ": number")
    .replace(/:\s*bool\b/g, ": boolean")
    .replace(/:\s*array\b/g, ": unknown[]")
    .replace(/:\s*json\b/g, ": unknown")
    .replace(/:\s*(text|uuid)\b/g, ": string")
    .replace(/:\s*Date\b/g, ": string");
}
const tsTypes = toTsTypes(typesContent);
writeFileSync(
  conv.client.typesOutput,
  "// GENERATED by manifest:client (manifest/scripts/generate-capsule-client.mjs) — DO NOT EDIT.\n" + tsTypes
);
const typeSet = new Set([...tsTypes.matchAll(/export interface (\w+)/g)].map((m) => m[1]));

// 2) CLIENT
const usedTypes = new Set();
const out = [];
out.push("// GENERATED by manifest:client — DO NOT EDIT. Matches Capsule conventions");
out.push("// (manifest/capsule-conventions.json): domain read paths, real envelopes,");
out.push("// dispatcher writes, apiFetch. Regenerate after IR/domain-map changes.");
out.push('import { apiFetch } from "@/app/lib/api";');
out.push('import { executeCommand } from "@/app/lib/manifest-client";');
out.push("__TYPE_IMPORT__");
out.push("");

// reads (domain-mapped entities)
for (const [entity, base] of Object.entries(ENTITY_DOMAIN_MAP)) {
  const T = typeSet.has(entity) ? entity : "Record<string, unknown>";
  if (typeSet.has(entity)) usedTypes.add(entity);
  const listKey = plural(camel(entity));
  const detailKey = camel(entity);
  out.push(`export async function list${plural(entity)}(query?: Record<string, string | number>): Promise<${T}[]> {`);
  out.push(`  const qs = query ? "?" + new URLSearchParams(Object.entries(query).map(([k, v]) => [k, String(v)])).toString() : "";`);
  out.push(`  const res = await apiFetch(\`/api/${base}/list\${qs}\`);`);
  out.push(`  if (!res.ok) throw new Error(\`Failed to list ${entity} (\${res.status})\`);`);
  out.push(`  const json = await res.json();`);
  out.push(`  return (json.${listKey} ?? json.data ?? []) as ${T}[];`);
  out.push(`}`);
  out.push(`export async function get${entity}(id: string): Promise<${T} | undefined> {`);
  out.push(`  const res = await apiFetch(\`/api/${base}/\${encodeURIComponent(id)}\`);`);
  out.push(`  if (!res.ok) throw new Error(\`Failed to get ${entity} (\${res.status})\`);`);
  out.push(`  const json = await res.json();`);
  out.push(`  return (json.${detailKey} ?? json.data) as ${T} | undefined;`);
  out.push(`}`);
}

// writes (all IR commands, via dispatcher unless overridden)
const overrides = conv.routePaths.commandOverrides || {};
const seen = new Set();
for (const c of ir.commands) {
  const key = `${c.entity}.${c.name}`;
  if (seen.has(key)) continue; seen.add(key);
  const T = typeSet.has(c.entity) ? c.entity : "unknown";
  if (typeSet.has(c.entity)) usedTypes.add(c.entity);
  const fn = `${camel(c.entity)}${cap(c.name)}`;
  const ov = overrides[key];
  const pathArg = ov ? `, { path: \`${ov.replace(/\{(\w+)\}/g, "${String(input.$1 ?? \"\")}")}\` }` : "";
  out.push(`export async function ${fn}(input: Record<string, unknown> = {}): Promise<${T} | undefined> {`);
  out.push(`  const r = await executeCommand<${T}>(${JSON.stringify(c.entity)}, ${JSON.stringify(c.name)}, input${pathArg});`);
  out.push(`  return r.result;`);
  out.push(`}`);
}

const importLine = usedTypes.size
  ? `import type { ${[...usedTypes].sort().join(", ")} } from "./manifest-types.generated";`
  : "";
writeFileSync(conv.client.clientOutput, out.join("\n").replace("__TYPE_IMPORT__", importLine) + "\n");

console.log("WROTE", conv.client.typesOutput, "(" + typeSet.size + " types)");
console.log("WROTE", conv.client.clientOutput, "(" + Object.keys(ENTITY_DOMAIN_MAP).length + " entities, " + seen.size + " commands)");
